import { type, type Type } from "arktype"
import { jsonSchemaToType } from "@ark/json-schema"

/**
 * Export an ArkType schema to a JSON Schema draft-2020-12 document.
 *
 * The returned object MUST contain `$schema` set to the draft-2020-12 URI:
 *   https://json-schema.org/draft/2020-12/schema
 */
export function exportJsonSchema(schema: Type): object {
  // schema.toJsonSchema() returns a JsonSchema object; by default it includes
  // $schema set to draft-2020-12. We explicitly pass the dialect option to be safe.
  const jsonSchema = schema.toJsonSchema({
    dialect: "https://json-schema.org/draft/2020-12/schema",
  })
  return jsonSchema as object
}

/**
 * Round-trip an ArkType schema through JSON Schema draft-2020-12 and back.
 *
 * 1. Export `schema` to JSON Schema via `exportJsonSchema()`.
 * 2. Re-parse the resulting JSON Schema back into an ArkType `Type`
 *    using `jsonSchemaToType` from `@ark/json-schema`.
 * 3. Return the re-parsed Type.
 */
export function roundTrip(schema: Type): Type {
  const jsonSchema = exportJsonSchema(schema)
  // jsonSchemaToType expects a JsonSchemaOrBoolean; we pass the full document
  // (which includes $schema, but $schema is just metadata and doesn't affect validation)
  return jsonSchemaToType(jsonSchema as any) as Type
}

import { type } from "arktype"
import { exportJsonSchema, roundTrip } from "./roundTrip.ts"

interface Input {
  schema: unknown
  corpus: unknown[]
}

interface Agreement {
  index: number
  originalAccept: boolean
  roundTrippedAccept: boolean
  agree: boolean
}

interface Output {
  jsonSchema: object
  agreements: Agreement[]
  allAgree: boolean
}

async function main(): Promise<void> {
  // Read all of stdin
  const chunks: Buffer[] = []
  for await (const chunk of process.stdin) {
    chunks.push(Buffer.from(chunk))
  }
  const raw = Buffer.concat(chunks).toString("utf-8")

  let input: Input
  try {
    input = JSON.parse(raw)
  } catch {
    process.stderr.write("Invalid JSON input on stdin\n")
    process.exit(1)
  }

  if (input.schema === undefined || !Array.isArray(input.corpus)) {
    process.stderr.write('Input must have shape { "schema": ..., "corpus": [...] }\n')
    process.exit(1)
  }

  // Build the original Type from the definition
  const original = type.raw(input.schema)

  // Obtain the intermediate JSON Schema document
  const jsonSchema = exportJsonSchema(original)

  // Round-trip: re-parse the JSON Schema back into an ArkType Type
  const roundTripped = roundTrip(original)

  // For each payload in the corpus, check agreement
  const agreements: Agreement[] = []
  let allAgree = true

  for (let i = 0; i < input.corpus.length; i++) {
    const payload = input.corpus[i]

    const originalResult = original(payload)
    const originalAccept = !(originalResult instanceof type.errors)

    const roundTrippedResult = roundTripped(payload)
    const roundTrippedAccept = !(roundTrippedResult instanceof type.errors)

    const agree = originalAccept === roundTrippedAccept

    if (!agree) {
      allAgree = false
    }

    agreements.push({
      index: i,
      originalAccept,
      roundTrippedAccept,
      agree,
    })
  }

  const output: Output = {
    jsonSchema,
    agreements,
    allAgree,
  }

  process.stdout.write(JSON.stringify(output) + "\n")

  if (!allAgree) {
    process.exit(1)
  }
}

main().catch((err) => {
  process.stderr.write(String(err) + "\n")
  process.exit(1)
})

