import { printable } from "@ark/util";
import { type } from "arktype";
import { jsonSchemaToType } from "./json.js";
const parseAllOfJsonSchema = (jsonSchemas) => jsonSchemas
    .map(jsonSchema => jsonSchemaToType(jsonSchema))
    .reduce((acc, validator) => acc.and(validator));
export const parseAnyOfJsonSchema = (jsonSchemas) => jsonSchemas
    .map(jsonSchema => jsonSchemaToType(jsonSchema))
    .reduce((acc, validator) => acc.or(validator));
const parseNotJsonSchema = (jsonSchema) => {
    const inner = jsonSchemaToType(jsonSchema);
    const jsonSchemaNotValidator = (data, ctx) => inner.allows(data) ?
        ctx.reject({
            expected: `not: ${inner.description}`,
            actual: printable(data)
        })
        : true;
    return type.unknown.narrow(jsonSchemaNotValidator);
};
const parseOneOfJsonSchema = (jsonSchemas) => {
    const oneOfValidators = jsonSchemas.map(nestedSchema => jsonSchemaToType(nestedSchema));
    const oneOfValidatorsDescriptions = oneOfValidators.map(validator => `○ ${validator.description}`);
    const jsonSchemaOneOfValidator = (data, ctx) => {
        let matchedValidator = undefined;
        for (const validator of oneOfValidators) {
            if (validator.allows(data)) {
                if (matchedValidator === undefined) {
                    matchedValidator = validator;
                    continue;
                }
                return ctx.reject({
                    expected: `exactly one of:\n${oneOfValidatorsDescriptions.join("\n")}`,
                    actual: `a value that matches against at least ${matchedValidator} and ${validator}`
                });
            }
        }
        return matchedValidator !== undefined;
    };
    return type.unknown.narrow(jsonSchemaOneOfValidator);
};
export const parseCompositionJsonSchema = (jsonSchema) => {
    if ("allOf" in jsonSchema)
        return parseAllOfJsonSchema(jsonSchema.allOf);
    if ("anyOf" in jsonSchema)
        return parseAnyOfJsonSchema(jsonSchema.anyOf);
    if ("not" in jsonSchema)
        return parseNotJsonSchema(jsonSchema.not);
    if ("oneOf" in jsonSchema)
        return parseOneOfJsonSchema(jsonSchema.oneOf);
};

